// Get workflow ID from input or set manually
const workflowId = $input.item.json.workflowId || 'YOUR_WORKFLOW_ID';

return {
  json: {
    workflowId: workflowId
  }
};

// Extract all nodes from the workflow
const workflow = $input.item.json;
const nodes = workflow.nodes || [];

// Create a list of nodes with their current names and types
const nodesList = nodes.map((node, index) => ({
  index: index,
  id: node.id,
  currentName: node.name,
  type: node.type,
  typeVersion: node.typeVersion,
  parameters: JSON.stringify(node.parameters).substring(0, 200) // First 200 chars for context
}));

return {
  json: {
    workflowName: workflow.name,
    totalNodes: nodes.length,
    nodes: nodesList
  }
};

// Prepare prompt for AI agent
const workflowName = $json.workflowName;
const nodes = $json.nodes;

// Create a structured list for the AI
const nodeDescriptions = nodes.map(node => 
  `${node.index + 1}. Current: "${node.currentName}" | Type: ${node.type} | Config: ${node.parameters}`
).join('\n');

const prompt = `You are helping rename nodes in an N8N workflow called "${workflowName}" to make them more descriptive and clear.

Here are the ${nodes.length} nodes in the workflow:

${nodeDescriptions}

For each node, suggest a more descriptive and meaningful name that:
1. Clearly describes what the node does based on its type and configuration
2. Is concise (2-6 words ideal)
3. Uses title case
4. Helps users understand the workflow flow at a glance

Respond in JSON format as an array of objects with this structure:
[
  {
    "index": 0,
    "currentName": "original name",
    "suggestedName": "Better Descriptive Name",
    "reason": "Brief explanation of why this name is better"
  }
]

Only suggest a new name if it would be significantly more descriptive than the current name.`;

return {
  json: {
    prompt: prompt,
    workflowName: workflowName,
    nodeCount: nodes.length
  }
};

// Parse AI response and format output
const aiResponse = $json.message?.content || $json.text || JSON.stringify($json);

let suggestions;
try {
  // Try to extract JSON from the response
  const jsonMatch = aiResponse.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    suggestions = JSON.parse(jsonMatch[0]);
  } else {
    suggestions = JSON.parse(aiResponse);
  }
} catch (error) {
  return {
    json: {
      error: 'Failed to parse AI response',
      rawResponse: aiResponse
    }
  };
}

return {
  json: {
    workflowName: $('Build AI Prompt').item.json.workflowName,
    totalSuggestions: suggestions.length,
    suggestions: suggestions,
    summary: suggestions.map(s => 
      `"${s.currentName}" → "${s.suggestedName}"`
    ).join('\n')
  }
};
